mapper.select:
SELECT * FROM question_bank
WHERE course_id = #{courseId}

    AND question_type = #{questionType}


    AND difficulty_level = #{difficultyLevel}


    AND point_id IN

        #{pointId}


ORDER BY created_at DESC

    LIMIT #{limit}

(
    SELECT * FROM question_bank
    WHERE course_id = #{courseId}
      AND question_type = #{questionType}
      AND difficulty_level = 'easy'
    ORDER BY RAND()
        LIMIT #{easyCount}
)
UNION ALL
(
    SELECT * FROM question_bank
    WHERE course_id = #{courseId}
      AND question_type = #{questionType}
      AND difficulty_level = 'medium'
    ORDER BY RAND()
        LIMIT #{mediumCount}
)
UNION ALL
(
    SELECT * FROM question_bank
    WHERE course_id = #{courseId}
      AND question_type = #{questionType}
      AND difficulty_level = 'hard'
    ORDER BY RAND()
        LIMIT #{hardCount}
)
